#include <print>
#include <string>
int main() {
    std::string name = "Alice";
    int age = 30;
    double score = 98.5;

    std::println("Name: {}", name);
    std::println("Age: {:>5}", age);
    std::println("Score: {:.1f}", score);
    std::print("No newline here");
    std::print(" — same line\n");
}

#include <print>

int main() {
    // Выравнивание текста
    std::println("{:<10} {:>10} {:^10}", "left", "right", "center");

    // Ведущие нули и фиксированная точность
    for (int i = 1; i <= 3; ++i) {
        std::println("Item {:02d}: {:>8.2f}", i, i * 3.14);
    }

    // Шестнадцатеричный и восьмеричный форматы
    int value = 255;
    std::println("Dec: {}  Hex: {:X}  Oct: {:o}", value, value, value);
}

#include <print>
#include <vector>
#include <map>
#include <string>
int main() {
    std::vector<int> nums = {1, 2, 3, 4, 5};
    std::println("{}", nums);     // со скобками
    std::println("{:n}", nums);   // без скобок
    std::println("{::>4}", nums); // каждый элемент выровнен вправо

    std::map<std::string, int> m = {{"a", 1}, {"b", 2}};
    std::println("{}", m);        // словарный стиль
}

#include <print>
#include <format>
#include <string>

struct Point {
    double x, y;
};

template<>
struct std::formatter<Point> {
    constexpr auto parse(std::format_parse_context& ctx) { return ctx.begin(); }
    auto format(const Point& p, std::format_context& ctx) const {
        return std::format_to(ctx.out(), "({:.1f}, {:.1f})", p.x, p.y);
    }
};

int main() {
    Point origin{0.0, 0.0};
    Point p{3.14, 2.72};

    std::println("{}", origin);
    std::println("{}", p);

    // Работает и внутри сложных форматных строк
    std::string result = std::format("A={}, B={}", Point{1.0, 2.0}, Point{3.0, 4.0});
    std::println("{}", result);
}

#include <print>
#include <format>
#include <array>
#include <string_view>
#include <cstdint>

struct Color {
    uint8_t r, g, b;
};

template<>
struct std::formatter<Color> {
    bool hex = false;
    constexpr auto parse(std::format_parse_context& ctx) {
        auto it = ctx.begin();
        if (it != ctx.end() && *it == 'x') { hex = true; ++it; }
        return it;
    }
    auto format(const Color& c, std::format_context& ctx) const {
        if (hex)
            return std::format_to(ctx.out(), "#{:02X}{:02X}{:02X}", c.r, c.g, c.b);
        return std::format_to(ctx.out(), "rgb({},{},{})", c.r, c.g, c.b);
    }
};

int main() {
    Color red{255, 0, 0};
    std::println("{}", red);    // формат по умолчанию
    std::println("{:x}", red);  // флаг x — шестнадцатеричный

    // format_to_n — запись в буфер без аллокации
    std::array<char, 32> buf{};
    auto result = std::format_to_n(buf.data(), buf.size() - 1, "{:x}", red);
    *result.out = '\0';
    std::println("buffered: {}", std::string_view(buf.data()));
}
